# runbook_audit.py — compare alert inventory against runbook inventory
import os
import re
from dataclasses import dataclass
from datetime import datetime, timedelta
from pathlib import Path
import yaml

@dataclass
class RunbookRecord:
    alert_name: str
    file_path: str
    last_verified: datetime | None
    owner: str | None

def parse_runbook_metadata(file_path: Path) -> RunbookRecord:
    """Extract metadata from the runbook header section."""
    content = file_path.read_text()
    alert_match = re.search(r'\*\*Alert:\*\*\s+(.+)', content)
    verified_match = re.search(r'\*\*Last verified:\*\*\s+(\d{4}-\d{2}-\d{2})', content)
    owner_match = re.search(r'\*\*Owner:\*\*\s+(.+)', content)

    return RunbookRecord(
        alert_name=alert_match.group(1).strip() if alert_match else "UNKNOWN",
        file_path=str(file_path),
        last_verified=datetime.strptime(verified_match.group(1), "%Y-%m-%d")
            if verified_match else None,
        owner=owner_match.group(1).strip() if owner_match else None,
    )

def audit_runbook_coverage(
    alert_rules_file: str,
    runbooks_dir: str,
    max_age_days: int = 90,
) -> dict:
    with open(alert_rules_file) as f:
        rules = yaml.safe_load(f)

    active_alerts = {
        rule["alert"]
        for group in rules.get("groups", [])
        for rule in group.get("rules", [])
        if "alert" in rule and rule.get("labels", {}).get("severity") in ("critical", "warning")
    }

    runbooks = {
        rb.alert_name: rb
        for path in Path(runbooks_dir).glob("**/*.md")
        for rb in [parse_runbook_metadata(path)]
    }

    cutoff = datetime.utcnow() - timedelta(days=max_age_days)
    gaps = []
    for alert_name in sorted(active_alerts):
        rb = runbooks.get(alert_name)
        if rb is None:
            gaps.append({"alert": alert_name, "issue": "NO RUNBOOK"})
        elif rb.last_verified is None:
            gaps.append({"alert": alert_name, "issue": "NO VERIFIED DATE"})
        elif rb.last_verified < cutoff:
            age = (datetime.utcnow() - rb.last_verified).days
            gaps.append({"alert": alert_name, "issue": f"STALE ({age} days)"})

    return {
        "total_alerts": len(active_alerts),
        "covered": len(active_alerts) - len(gaps),
        "gaps": gaps,
    }

# Usage
result = audit_runbook_coverage(
    alert_rules_file="monitoring/prometheus-alerts.yaml",
    runbooks_dir="runbooks/claude-integration/",
)
print(f"Coverage: {result['covered']}/{result['total_alerts']} alerts have current runbooks")
for gap in result["gaps"]:
    print(f"  MISSING: {gap['alert']} — {gap['issue']}")
